using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
        }

        [Theory]
        [InlineData(1, false)]
        [InlineData(2, true)]
        [InlineData(3, true)]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<string>(new List<string>(), 30, pageIndex, 10);
            Assert.Equal(expected, list.HasPreviousPage);
        }

        [Theory]
        [InlineData(1, 3, true)]
        [InlineData(2, 3, true)]
        [InlineData(3, 3, false)]
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
        {
            // totalPages = ceil(count/pageSize). For totalPages=3 with pageSize=10, count=30.
            var list = new PaginatedList<string>(new List<string>(), totalPages * 10, pageIndex, 10);
            Assert.Equal(expected, list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page1 = PaginatedList<int>.Create(source, 1, 10);
            Assert.Equal(10, page1.Count);
            Assert.Equal(1, page1.PageIndex);
            Assert.Equal(3, page1.TotalPages);
            Assert.False(page1.HasPreviousPage);
            Assert.True(page1.HasNextPage);
            Assert.Equal(1, page1[0]);
            Assert.Equal(10, page1[9]);
        }

        [Fact]
        public void Create_LastPage_HasCorrectItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page3 = PaginatedList<int>.Create(source, 3, 10);
            Assert.Equal(5, page3.Count);
            Assert.Equal(3, page3.PageIndex);
            Assert.True(page3.HasPreviousPage);
            Assert.False(page3.HasNextPage);
            Assert.Equal(21, page3[0]);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _sut = new();

        public void Dispose()
        {
            // Drain the static queue to minimize cross-test pollution
            while (_sut.ReceiveNotification() != null) { }
            _sut.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
            var notification = _sut.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE);
            var notification = _sut.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation op, string expectedVerb)
        {
            _sut.SendNotification("Dept", "1", "Math", op, "user");
            var notification = _sut.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains(expectedVerb, notification.Message);
        }

        [Fact]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Drain any existing notifications first
            while (_sut.ReceiveNotification() != null) { }

            Assert.Null(_sut.ReceiveNotification());
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op; just verify it doesn't throw
            var ex = Record.Exception(() => _sut.MarkAsRead(999));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("X", "1", EntityOperation.CREATE, null);
            var notification = _sut.ReceiveNotification();

            Assert.Equal("System", notification.CreatedBy);
        }
    }
}

