        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestHelper.CreateContext();
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_NoStudents_ReturnsEmptyList()
        {
            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>>(viewResult.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void About_WithStudents_ReturnsGroupedData()
        {
            var date1 = new DateTime(2023, 9, 1);
            var date2 = new DateTime(2024, 1, 15);
            _context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = date1 },
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = date1 },
                new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = date2 }
            );
            _context.SaveChanges();

            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>>(viewResult.Model);
            Assert.Equal(2, model.Count);
            Assert.Contains(model, g => g.EnrollmentDate == date1 && g.StudentCount == 2);
            Assert.Contains(model, g => g.EnrollmentDate == date2 && g.StudentCount == 1);
        }

