            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedStudents()
        {
            _context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2019, 9, 1) },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2017, 9, 1) },
                new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2018, 9, 1) },
                new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2018, 9, 1) },
                new Student { LastName = "Justice", FirstMidName = "Peggy", EnrollmentDate = new DateTime(2016, 9, 1) }
            );
            _context.SaveChanges();
        }

        // --- Index ---

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            SeedStudents();

            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            SeedStudents();

            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Li", model[0].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            SeedStudents();

            var result = _controller.Index("Date", null, null, null);

