            _mockEnv.Setup(e => e.WebRootPath).Returns((string)null);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Department SeedDepartment()
        {
            var dept = new Department { Name = "Engineering", Budget = 100000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        private Course SeedCourse(Department dept = null)
        {
            dept ??= SeedDepartment();
            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var dept = SeedDepartment();
            SeedCourse(dept);

            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.Single(model);
