        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            SeedCourse();

            var result = _controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            SeedDepartment();

            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            var dept = SeedDepartment();
            var course = new Course { CourseID = 2000, Title = "Physics", Credits = 4, DepartmentID = dept.DepartmentID };

            var result = _controller.Create(course, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.NotNull(_context.Courses.Find(2000));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var dept = SeedDepartment();
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2001, DepartmentID = dept.DepartmentID };

            var result = _controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var dept = SeedDepartment();
            var course = new Course { CourseID = 2002, Title = "Art", Credits = 2, DepartmentID = dept.DepartmentID };

            var mockFile = CreateMockFormFile("test.exe", 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_OversizedFile_ReturnsViewWithError()
        {
            var dept = SeedDepartment();
            var course = new Course { CourseID = 2003, Title = "Music", Credits = 2, DepartmentID = dept.DepartmentID };

            var mockFile = CreateMockFormFile("image.jpg", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            SeedCourse();

            var result = _controller.Edit(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            var dept = SeedDepartment();
            var course = new Course { CourseID = 3000, Title = "Biology", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updated = new Course { CourseID = 3000, Title = "Bio Updated", Credits = 4, DepartmentID = dept.DepartmentID };

            var result = _controller.Edit(updated, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidExtension_ReturnsViewWithError()
        {
            var dept = SeedDepartment();
            var course = new Course { CourseID = 3001, Title = "Test", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var mockFile = CreateMockFormFile("bad.pdf", 1024);
            var updated = new Course { CourseID = 3001, Title = "Test", Credits = 1, DepartmentID = dept.DepartmentID };

            var result = _controller.Edit(updated, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsView()
        {
            SeedCourse();

            var result = _controller.Delete(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            SeedCourse();

            var result = _controller.DeleteConfirmed(1050);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        // --- Helper ---

        private static Mock<IFormFile> CreateMockFormFile(string fileName, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mock;
        }
    }
}

