using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelper.CreateContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor SeedInstructor(bool withCourses = false)
        {
            var dept = new Department { Name = "Engineering", Budget = 100000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);

            var instructor = new Instructor
            {
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = new DateTime(2002, 7, 6),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            if (withCourses)
            {
                var course = new Course
                {
                    CourseID = 1045,
                    Title = "Calculus",
                    Credits = 4,
                    DepartmentID = dept.DepartmentID,
                    Enrollments = new List<Enrollment>()
                };
                _context.Courses.Add(course);
                _context.SaveChanges();

                _context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID });
                _context.SaveChanges();
            }

            return instructor;
        }

        // --- Index ---

        [Fact]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            SeedInstructor();

            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Single(model.Instructors);
            Assert.Null(model.Courses);
            Assert.Null(model.Enrollments);
        }

        [Fact]
        public void Index_WithInstructorSelected_ShowsCourses()
        {
            var instructor = SeedInstructor(withCourses: true);

            var result = _controller.Index(instructor.ID, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithCourseSelected_ShowsEnrollments()
        {
            var instructor = SeedInstructor(withCourses: true);
            var course = _context.Courses.First();

            // Add an enrollment
            var student = new Student { LastName = "Test", FirstMidName = "S", EnrollmentDate = DateTime.Today };
            _context.Students.Add(student);
            _context.SaveChanges();
            _context.Enrollments.Add(new Enrollment { CourseID = course.CourseID, StudentID = student.ID, Grade = Grade.A });
            _context.SaveChanges();

            var result = _controller.Index(instructor.ID, course.CourseID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            var instructor = SeedInstructor();

            var result = _controller.Details(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Fakhouri", model.LastName);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithCourseData()
        {
            var dept = new Department { Name = "Eng", Budget = 100000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);
            var course = new Course { CourseID = 5000, Title = "Test", Credits = 3, DepartmentID = 0 };
            _context.SaveChanges();
            course.DepartmentID = dept.DepartmentID;
            _context.Courses.Add(course);
            _context.SaveChanges();

            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "New",
                FirstMidName = "Instructor",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsAssignments()
        {
            var dept = new Department { Name = "Eng", Budget = 100000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            var course = new Course { CourseID = 6000, Title = "Assigned", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var instructor = new Instructor
            {
                LastName = "New2",
                FirstMidName = "Test",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, new[] { "6000" });

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);

            var saved = _context.Instructors.Include(i => i.CourseAssignments)
                .First(i => i.LastName == "New2");
            Assert.Single(saved.CourseAssignments);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "NoLast",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = SeedInstructor(withCourses: true);

            var result = _controller.Edit(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Fakhouri", model.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsView()
        {
            var instructor = SeedInstructor();

            var result = _controller.Delete(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Instructor>(viewResult.Model);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var instructor = SeedInstructor();

            var result = _controller.DeleteConfirmed(instructor.ID);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Instructors.Find(instructor.ID));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            var instructor = SeedInstructor();
            var dept = _context.Departments.First();
            dept.InstructorID = instructor.ID;
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

