+        [InlineData(1, 3, true)]
+        [InlineData(2, 3, true)]
+        [InlineData(3, 3, false)]
+        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
+        {
+            // totalPages = ceil(count/pageSize). For totalPages=3 with pageSize=10, count=30.
+            var list = new PaginatedList<string>(new List<string>(), totalPages * 10, pageIndex, 10);
+            Assert.Equal(expected, list.HasNextPage);
+        }
+
+        [Fact]
+        public void Create_ReturnsCorrectPage()
+        {
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            var page1 = PaginatedList<int>.Create(source, 1, 10);
+            Assert.Equal(10, page1.Count);
+            Assert.Equal(1, page1.PageIndex);
+            Assert.Equal(3, page1.TotalPages);
+            Assert.False(page1.HasPreviousPage);
+            Assert.True(page1.HasNextPage);
+            Assert.Equal(1, page1[0]);
+            Assert.Equal(10, page1[9]);
+        }
+
+        [Fact]
+        public void Create_LastPage_HasCorrectItems()
+        {
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            var page3 = PaginatedList<int>.Create(source, 3, 10);
+            Assert.Equal(5, page3.Count);
+            Assert.Equal(3, page3.PageIndex);
+            Assert.True(page3.HasPreviousPage);
+            Assert.False(page3.HasNextPage);
+            Assert.Equal(21, page3[0]);
+        }
+
+        [Fact]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            var source = Enumerable.Empty<int>().AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.Empty(result);
+            Assert.Equal(1, result.PageIndex);
+            Assert.Equal(0, result.TotalPages);
+            Assert.False(result.HasPreviousPage);
+            Assert.False(result.HasNextPage);
+        }
+    }
+}
